import React, { useState } from "react";

const services = [
  {
    tag: "Build",
    title: "I'll build it for you.",
    summary: "You bring the problem. I design and build the AI system that solves it.",
    details: [
      { label: "Agentic Systems", text: "AI agents that act autonomously, use tools, and complete tasks without you in the loop." },
      { label: "Automation Pipelines", text: "End-to-end workflows across n8n, Make, and Zapier that replace manual, repetitive work." },
      { label: "MCP Architecture", text: "Multi-agent systems built on the Model Context Protocol, designed to scale." },
      { label: "AI Content Systems", text: "Automated pipelines that produce, format, and publish content on a schedule." },
      { label: "LLM Evaluation", text: "Frameworks that measure whether your AI is actually working, structured and repeatable." }
    ],
    cta: "Get in touch",
    ctaType: "contact"
  },
  {
    tag: "Consult",
    title: "I'll guide you through it.",
    summary: "Not sure where to start? I'll help you figure out where AI fits and how to make it work for you.",
    details: [
      { label: "Strategy Sessions", text: "A focused session to map out where AI can have the biggest impact in your business. You leave with clarity, not a sales pitch." },
      { label: "Workshops", text: "Hands-on sessions for teams who want to actually use AI day-to-day. Practical, relevant, built around your tools." },
      { label: "Advisory", text: "Ongoing support as you implement AI. Someone who's done it before, in your corner." }
    ],
    cta: "Book a free discovery call",
    ctaType: "calendly"
  }
];

export default function Services() {
  const [expanded, setExpanded] = useState(null);

  function toggle(i) {
    setExpanded(expanded === i ? null : i);
  }

  return (
    <section
      id="services"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #252A40",
        scrollMarginTop: "70px"
      }}
    >
      {/* Header */}
      <div className="mb-12" style={{ maxWidth: "48ch" }}>
        <p className="eyebrow mb-4">Services</p>
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(1.6rem, 3.5vw, 2.8rem)",
            fontWeight: 700,
            letterSpacing: "-0.025em",
            color: "#F0F0EC",
            lineHeight: 1.1
          }}
        >
          Two ways I can help.
        </h2>
      </div>

      {/* Service cards */}
      <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
        {services.map((s, i) => (
          <div
            key={s.tag}
            className="card"
            style={{
              padding: "0",
              overflow: "hidden",
              borderColor: expanded === i ? "rgba(91, 141, 239, 0.25)" : "#252A40",
              transition: "border-color 0.2s ease"
            }}
          >
            {/* Card header — always visible */}
            <button
              onClick={() => toggle(i)}
              style={{
                width: "100%",
                padding: "2rem 2.5rem",
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                gap: "1.5rem",
                background: "none",
                border: "none",
                cursor: "pointer",
                textAlign: "left"
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: "2rem", flexWrap: "wrap" }}>
                <span
                  style={{
                    fontFamily: "'JetBrains Mono', monospace",
                    fontSize: "0.65rem",
                    letterSpacing: "0.14em",
                    textTransform: "uppercase",
                    color: "#5B8DEF",
                    background: "rgba(91, 141, 239, 0.08)",
                    border: "1px solid rgba(91, 141, 239, 0.2)",
                    padding: "0.25rem 0.65rem",
                    borderRadius: "0.25rem",
                    flexShrink: 0
                  }}
                >
                  {s.tag}
                </span>
                <div>
                  <h3
                    style={{
                      fontFamily: "'Space Grotesk', sans-serif",
                      fontWeight: 700,
                      fontSize: "clamp(1.1rem, 2.5vw, 1.5rem)",
                      color: "#F0F0EC",
                      letterSpacing: "-0.02em",
                      marginBottom: "0.25rem"
                    }}
                  >
                    {s.title}
                  </h3>
                  <p
                    style={{
                      fontFamily: "'Inter', sans-serif",
                      fontSize: "0.9rem",
                      color: "#8A8AB0"
                    }}
                  >
                    {s.summary}
                  </p>
                </div>
              </div>

              {/* Expand icon */}
              <div
                style={{
                  width: "36px",
                  height: "36px",
                  borderRadius: "50%",
                  border: "1px solid #252A40",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flexShrink: 0,
                  transition: "transform 0.2s ease, border-color 0.2s ease",
                  transform: expanded === i ? "rotate(45deg)" : "rotate(0deg)",
                  borderColor: expanded === i ? "rgba(91, 141, 239, 0.3)" : "#252A40"
                }}
              >
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
                  <line x1="7" y1="1" x2="7" y2="13" stroke="#5B8DEF" strokeWidth="1.5" strokeLinecap="round" />
                  <line x1="1" y1="7" x2="13" y2="7" stroke="#5B8DEF" strokeWidth="1.5" strokeLinecap="round" />
                </svg>
              </div>
            </button>

            {/* Expanded content */}
            {expanded === i && (
              <div
                style={{
                  padding: "0 2.5rem 2rem",
                  borderTop: "1px solid #252A40"
                }}
              >
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 260px), 1fr))",
                    gap: "1rem",
                    marginTop: "1.5rem",
                    marginBottom: "2rem"
                  }}
                >
                  {s.details.map((d) => (
                    <div
                      key={d.label}
                      style={{
                        padding: "1.25rem",
                        background: "#111320",
                        border: "1px solid #252A40",
                        borderRadius: "0.5rem"
                      }}
                    >
                      <p
                        style={{
                          fontFamily: "'JetBrains Mono', monospace",
                          fontSize: "0.65rem",
                          letterSpacing: "0.12em",
                          textTransform: "uppercase",
                          color: "#5B8DEF",
                          marginBottom: "0.5rem"
                        }}
                      >
                        {d.label}
                      </p>
                      <p
                        style={{
                          fontFamily: "'Inter', sans-serif",
                          fontSize: "0.875rem",
                          color: "#8A8AB0",
                          lineHeight: 1.65
                        }}
                      >
                        {d.text}
                      </p>
                    </div>
                  ))}
                </div>

                {/* CTA */}
                {s.ctaType === "contact" ? (
                  <button
                    onClick={() => {
                      const event = new CustomEvent("openContact");
                      window.dispatchEvent(event);
                    }}
                    style={{
                      fontFamily: "'Space Grotesk', sans-serif",
                      fontWeight: 600,
                      fontSize: "0.95rem",
                      background: "#5B8DEF",
                      color: "#111320",
                      padding: "0.75rem 1.75rem",
                      borderRadius: "0.375rem",
                      border: "none",
                      cursor: "pointer",
                      transition: "opacity 0.15s ease"
                    }}
                    onMouseEnter={e => e.currentTarget.style.opacity = "0.88"}
                    onMouseLeave={e => e.currentTarget.style.opacity = "1"}
                  >
                    {s.cta} →
                  </button>
                ) : (
                  /* TODO: Replace # with your Calendly URL before launch */
                  <a
                    href="#"
                    target="_blank"
                    rel="noopener noreferrer"
                    style={{
                      display: "inline-flex",
                      alignItems: "center",
                      gap: "0.5rem",
                      fontFamily: "'Space Grotesk', sans-serif",
                      fontWeight: 600,
                      fontSize: "0.95rem",
                      background: "#5B8DEF",
                      color: "#111320",
                      padding: "0.75rem 1.75rem",
                      borderRadius: "0.375rem",
                      textDecoration: "none",
                      transition: "opacity 0.15s ease"
                    }}
                    onMouseEnter={e => e.currentTarget.style.opacity = "0.88"}
                    onMouseLeave={e => e.currentTarget.style.opacity = "1"}
                  >
                    {s.cta} →
                  </a>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </section>
  );
}
